int quick(int left, int right) {
    if (left >= right) return 0;
    int pivot = data[left];
    int l_cursor = left;
    int r_cursor = right;
    while (1) {
        while (data[l_cursor] < pivot)
            l_cursor++;
        while (data[r_cursor] > pivot)
            r_cursor--;
        if (l_cursor >= r_cursor) break;
        int temp = data[l_cursor];
        data[l_cursor] = data[r_cursor];
        data[r_cursor] = temp;
        l_cursor++;
        r_cursor--;
    }
    quick(left, l_cursor - 1);
    quick(r_cursor + 1, right);
    return 0;
}

int main(void) {
    quick(0, 19999);
    return data[0] + data[19999];
}

